func cmdRm(filename string) {
	indexData, _ := os.ReadFile(".minigit/index")
	content := strings.TrimRight(string(indexData), "\n")
	if content == "" {
		fmt.Println("File not in index")
		os.Exit(1)
	}
	lines := strings.Split(content, "\n")
	var newLines []string
	found := false
	for _, l := range lines {
		if l == filename {
			found = true
		} else {
			newLines = append(newLines, l)
		}
	}
	if !found {
		fmt.Println("File not in index")
		os.Exit(1)
	}
	if len(newLines) == 0 {
		os.WriteFile(".minigit/index", []byte{}, 0644)
	} else {
		os.WriteFile(".minigit/index", []byte(strings.Join(newLines, "\n")+"\n"), 0644)
	}
}

func cmdShow(commitHash string) {
	data, err := os.ReadFile(filepath.Join(".minigit", "commits", commitHash))
	if err != nil {
		fmt.Println("Invalid commit")
		os.Exit(1)
	}
	lines := strings.Split(string(data), "\n")
	var timestamp, message string
	var fileEntries []string
	inFiles := false
	for _, line := range lines {
		if strings.HasPrefix(line, "timestamp: ") {
			timestamp = strings.TrimPrefix(line, "timestamp: ")
		} else if strings.HasPrefix(line, "message: ") {
			message = strings.TrimPrefix(line, "message: ")
		} else if line == "files:" {
			inFiles = true
		} else if inFiles && line != "" {
			fileEntries = append(fileEntries, line)
		}
	}
	sort.Strings(fileEntries)
	fmt.Printf("commit %s\nDate: %s\nMessage: %s\nFiles:\n", commitHash, timestamp, message)
	for _, f := range fileEntries {
		fmt.Printf("  %s\n", f)
	}
}

